mapper.select:
SELECT a.id AS articleId, a.title, a.summary, a.cover, a.create_time AS createTime, a.audit_status AS auditStatus, a.is_published AS isPublished, a.views, a.likes, a.comments, a.collects FROM t_article a WHERE a.user_id = #{userId}
AND a.is_published = #{isPublished}
AND ( a.title LIKE CONCAT('%', #{keyword}, '%') OR a.summary LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY a.create_time DESC
